// 메시지 유형 분류: command, mr-review, alert-bot, ticket-reaction, general, skip
const body = $input.item.json.body || {};
const eventType = body.eventType || '';

// :ticket: 리액션 이벤트 처리 → Jira 이슈 생성
if (eventType === 'REACTION_ADDED' && body.reaction === 'ticket') {
  console.log('Ticket reaction detected:', JSON.stringify({ channel: body.channel, timestamp: body.timestamp, reaction: body.reaction }));
  return { 
    json: { 
      ...body, 
      messageType: 'ticket-reaction',
      targetChannel: body.channel,
      targetMessageTs: body.timestamp,
      reactionUser: body.user
    } 
  };
}

// :hammer_and_wrench: 리액션 이벤트 처리 → 자동 수정 파이프라인
if (eventType === 'REACTION_ADDED' && body.reaction === 'hammer_and_wrench') {
  console.log('Auto-fix reaction detected:', JSON.stringify({ channel: body.channel, timestamp: body.timestamp, reaction: body.reaction }));
  return { 
    json: { 
      ...body, 
      messageType: 'autofix-reaction',
      targetChannel: body.channel,
      targetMessageTs: body.timestamp,
      reactionUser: body.user
    } 
  };
}

// 그 외 리액션 이벤트는 스킵 (피드백 핸들러에서 처리)
if (eventType.includes('REACTION')) {
  return { json: { ...body, messageType: 'skip', skipReason: 'reaction event (not ticket)' } };
}

// 알람 봇 메시지 감지 (ALERT_BOT_MESSAGE 타입)
if (eventType === 'ALERT_BOT_MESSAGE') {
  const text = body.text || '';
  // 에러/장애 키워드 확인
  const errorKeywords = ['error', 'exception', 'failed', 'failure', 'critical', 'alert', '장애', '오류', '에러', '실패', 'Failure', 'ERROR', 'CRITICAL', 'WARNING'];
  const hasErrorKeyword = errorKeywords.some(kw => text.toLowerCase().includes(kw.toLowerCase()));

  if (hasErrorKeyword) {
    return { json: { ...body, messageType: 'alert-bot', isAlertBot: true, botId: body.botId } };
  }
  // 에러 키워드 없으면 스킵
  return { json: { ...body, messageType: 'skip', skipReason: 'bot message without error keywords' } };
}

const text = (body.text || '').replace(/<@[A-Z0-9]+>/gi, '').trim();

// 빈 텍스트는 스킵
if (!text) {
  return { json: { ...body, messageType: 'skip', skipReason: 'empty text' } };
}

// 기본 결과 객체
const result = { ...body, messageType: 'general', isMrReview: false, isAlertBot: false };

// 1. 명령어 체크 (/로 시작)
if (text.charAt(0) === '/') {
  result.messageType = 'command';
  return { json: result };
}

// 2. MR 리뷰 요청 체크
const mrPatterns = [
  /!([0-9]+)/,
  /MR\s*#?([0-9]+)/i,
  /merge_requests?\/([0-9]+)/i
];

// 프로젝트 힌트 추출
const projectPatterns = [
  /\[프로젝트:\s*([^\]]+)\]/i,
  /([a-z][a-z0-9-]*-server)/i,
  /([a-z][a-z0-9-]+)\s+!\d+/i
];

let projectHint = null;
for (const pattern of projectPatterns) {
  const match = text.match(pattern);
  if (match) {
    projectHint = match[1].toLowerCase().trim();
    break;
  }
}

// MR 번호 추출
let mrNumber = null;
for (const pattern of mrPatterns) {
  const match = text.match(pattern);
  if (match) {
    mrNumber = match[1];
    break;
  }
}

if (mrNumber) {
  const reviewKeywords = ['리뷰', 'review', '검토', '봐줘', '확인', '코드리뷰', 'cr ', 'code review'];
  const hasReviewKeyword = reviewKeywords.some(k => text.toLowerCase().includes(k.toLowerCase()));

  if (hasReviewKeyword) {
    result.messageType = 'mr-review';
    result.isMrReview = true;
    result.mrNumber = mrNumber;
    result.projectHint = projectHint;
    return { json: result };
  }
}

return { json: result };

// MR 컨텍스트 조회 (scheduled-mr-review와 동일한 방식)
const classifyData = $('Classify Message').first().json;
const apiUrl = process.env.CLAUDE_FLOW_API_URL || 'http://host.docker.internal:8080';

const mrNumber = classifyData.mrNumber;
let project = classifyData.projectHint;

if (!project) {
  project = process.env.GITLAB_GROUP || 'team/project';
}

console.log('Fetching MR context:', project, mrNumber);

try {
  const contextUrl = `${apiUrl}/api/v1/mr-review/context/${encodeURIComponent(project)}/${mrNumber}`;
  const contextResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: contextUrl,
    json: true,
    timeout: 120000
  });

  if (!contextResponse.success || !contextResponse.context) {
    return {
      json: {
        error: contextResponse.error || 'MR 컨텍스트 조회 실패',
        mrNumber: mrNumber,
        project: project
      }
    };
  }

  return {
    json: {
      mrNumber: mrNumber,
      project: project,
      mrContext: contextResponse.context,
      mrTitle: contextResponse.mrTitle,
      mrUrl: contextResponse.mrUrl,
      issueCount: contextResponse.issueCount || 0,
      fileCount: contextResponse.fileCount || 0
    }
  };
} catch (e) {
  return {
    json: {
      error: e.message,
      mrNumber: mrNumber,
      project: project
    }
  };
}

// AI 리뷰 실행
const mrData = $input.item.json;
const apiUrl = process.env.CLAUDE_FLOW_API_URL || 'http://host.docker.internal:8080';

const reviewPrompt = `## MR 리뷰 요청\n\n**프로젝트**: ${mrData.project}\n**MR**: !${mrData.mrNumber} - ${mrData.mrTitle || ''}\n**URL**: ${mrData.mrUrl || ''}\n\n---\n\n${mrData.mrContext}\n\n---\n\n위 MR 분석 결과를 바탕으로 코드 리뷰를 작성해주세요.\n\n**리뷰 형식:**\n### 요약\n### 장점\n### 개선 사항\n### 전체 평가 (⭐/10)`;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: apiUrl + '/api/v1/chat/execute',
    body: {
      messages: [{ role: 'user', content: reviewPrompt }],
      projectId: mrData.project,
      agentId: 'code-reviewer',
      skipMrAnalysis: true,
      source: 'slack'
    },
    json: true,
    timeout: 600000
  });

  if (!response.success || !response.content) {
    return { json: { ...mrData, error: response.error || 'AI 리뷰 실패' } };
  }

  return {
    json: {
      ...mrData,
      aiReview: response.content,
      reviewSuccess: true
    }
  };
} catch (e) {
  return { json: { ...mrData, error: e.message } };
}

// GitLab에 코멘트 작성
const mrData = $input.item.json;
const apiUrl = process.env.CLAUDE_FLOW_API_URL || 'http://host.docker.internal:8080';

if (!mrData.reviewSuccess || mrData.error) {
  return { json: mrData };
}

const gitlabComment = `## 🤖 AI Code Review\n\n${mrData.aiReview}\n\n---\n_Generated by Claude Flow_`;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: apiUrl + '/api/v1/plugins/gitlab/execute',
    body: {
      command: 'mr-comment',
      args: {
        project: mrData.project,
        mr_id: mrData.mrNumber,
        comment: gitlabComment
      }
    },
    json: true,
    timeout: 30000
  });

  // 라벨 적용
  await this.helpers.httpRequest({
    method: 'POST',
    url: apiUrl + '/api/v1/plugins/gitlab/execute',
    body: {
      command: 'mr-add-label',
      args: {
        project: mrData.project,
        mr_id: mrData.mrNumber,
        label: 'ai-review::done'
      }
    },
    json: true,
    timeout: 10000
  });
} catch (e) {
  console.log('GitLab comment error:', e.message);
}

return { json: mrData };

