// 스레드 히스토리를 대화 형식으로 변환
const webhookBody = $('Webhook').item.json.body;
const historyResponse = $input.item.json;

let conversationHistory = [];

if (historyResponse && historyResponse.success && historyResponse.messages && historyResponse.messages.length > 1) {
  const previousMessages = historyResponse.messages.slice(0, -1);
  conversationHistory = previousMessages.map(msg => ({
    role: msg.isBot ? 'assistant' : 'user',
    content: msg.text.replace(/<@[A-Z0-9]+>/g, '').trim(),
    userName: msg.userName || msg.user
  })).filter(msg => msg.content.length > 0);
}

return {
  json: {
    channel: webhookBody.channel,
    text: webhookBody.text,
    threadTs: webhookBody.threadTs || webhookBody.timestamp,
    timestamp: webhookBody.timestamp,
    user: webhookBody.user,
    conversationHistory: conversationHistory
  }
};

// 프로젝트 조회 결과 병합
const projectResponse = $input.item.json;
const alertData = $('Classify Message').item.json;

// 프로젝트가 없으면 (404 또는 에러) 스킵
const hasProject = projectResponse.projectId != null;

return {
  json: {
    shouldProcess: hasProject,
    channel: alertData.channel,
    botId: alertData.botId,
    text: alertData.text,
    messageTs: alertData.timestamp,
    threadTs: alertData.threadTs || alertData.timestamp,
    // 프로젝트 정보
    projectId: projectResponse.projectId,
    projectName: projectResponse.projectName,
    jiraProject: projectResponse.jiraProject,
    gitlabPath: projectResponse.gitlabPath,
    workingDirectory: projectResponse.workingDirectory,
    defaultBranch: projectResponse.defaultBranch,
    envBranchMapping: projectResponse.envBranchMapping || {},
    reason: hasProject ? null : 'Channel not mapped to any project'
  }
};

const response = $input.item.json;
console.log('Raw response:', JSON.stringify(response, null, 2));

// HTTP Request 노드는 응답을 그대로 반환
const text = response.content || response.response || response.output || '';
console.log('Extracted text:', text.substring(0, 200));

// JSON 추출
const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/) || text.match(/\{[\s\S]*\}/);
console.log('JSON match found:', !!jsonMatch);
let analysis = {};

try {
  const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : text;
  console.log('Parsing JSON:', jsonStr.substring(0, 100));
  analysis = JSON.parse(jsonStr.trim());
  console.log('Parsed analysis:', JSON.stringify(analysis));
} catch (e) {
  console.log('Parse error:', e.message);
  analysis = {
    isActionable: false,
    error: 'Failed to parse analysis: ' + e.message
  };
}

// 이전 노드의 메시지 및 프로젝트 정보 가져오기
const projectData = $('Merge Alert Project').item.json;

// 환경 기반 브랜치 결정 (envBranchMapping 사용)
const environment = analysis.environment?.toLowerCase() || null;
const envBranchMapping = projectData.envBranchMapping || {};
const targetBranch = environment ? (envBranchMapping[environment] || projectData.defaultBranch || 'develop') : (projectData.defaultBranch || 'develop');
console.log('Environment:', environment, 'Target branch:', targetBranch);

return {
  json: {
    ...analysis,
    environment: environment,
    targetBranch: targetBranch,
    channel: projectData.channel,
    messageTs: projectData.messageTs,
    threadTs: projectData.threadTs,
    originalText: projectData.text,
    // 프로젝트 정보 전달
    projectId: projectData.projectId,
    projectName: projectData.projectName,
    jiraProject: projectData.jiraProject,
    gitlabPath: projectData.gitlabPath,
    workingDirectory: projectData.workingDirectory,
    defaultBranch: projectData.defaultBranch,
    envBranchMapping: envBranchMapping
  }
};

// 액션 불필요 또는 분석 실패 로깅
const data = $input.item.json;
console.log('Alert not actionable or analysis failed:', data);
return { json: { skipped: true, reason: data.error || 'Not actionable', channel: data.channel } };

// 프로젝트 미등록 채널 로깅
const data = $input.item.json;
console.log('Alert channel not mapped to project:', data.channel);
return { json: { skipped: true, reason: 'Channel not mapped to project', channel: data.channel } };

// 리액션된 메시지에서 분석 데이터 추출
const messageResponse = $input.item.json;
const classifyData = $('Classify Message').item.json;

console.log('Get reacted message response:', JSON.stringify(messageResponse, null, 2));

if (!messageResponse.success || !messageResponse.text) {
  return {
    json: {
      error: 'Failed to get message content',
      channel: classifyData.targetChannel,
      threadTs: classifyData.targetMessageTs
    }
  };
}

const text = messageResponse.text;

// 분석 결과 메시지 파싱
// 형식: *심각도:* HIGH, *프로젝트:* Name (`id`), *제목:* ...
const severityMatch = text.match(/\*심각도:\*\s*(\w+)/);
const projectMatch = text.match(/\*프로젝트:\*\s*([^(]+)\s*\(`([^`]+)`\)/);
const jiraMatch = text.match(/\*Jira:\*\s*(\w+)/);
const errorTypeMatch = text.match(/\*에러 타입:\*\s*([^\n]+)/);
const summaryMatch = text.match(/\*제목:\*\s*([^\n]+)/);
const descMatch = text.match(/\*설명:\*\n([\s\S]*?)(?=\n\n\*수정 제안:|\n---)/); 
const fixMatch = text.match(/\*수정 제안:\*\n([\s\S]*?)(?=\n---|$)/);

const severity = severityMatch ? severityMatch[1].trim() : 'MEDIUM';
const projectName = projectMatch ? projectMatch[1].trim() : 'Unknown';
const projectId = projectMatch ? projectMatch[2].trim() : null;
const jiraProject = jiraMatch ? jiraMatch[1].trim() : 'PROJ';
const errorType = errorTypeMatch ? errorTypeMatch[1].trim() : 'Unknown';
const summary = summaryMatch ? summaryMatch[1].trim() : '장애 알람';
const description = descMatch ? descMatch[1].trim() : text;
const suggestedFix = fixMatch ? fixMatch[1].trim() : '';

// 심각도에 따른 Jira 우선순위 ID 매핑 (Jira는 우선순위 ID를 사용)
const priorityMap = {
  'CRITICAL': '10000',  // Highest
  'HIGH': '10001',       // High
  'MEDIUM': '10002',     // Medium
  'LOW': '10003'         // Low
};

return {
  json: {
    // Jira 이슈 생성용 데이터
    jiraProject: jiraProject,
    summary: `[${errorType}] ${summary}`,
    description: `h2. 장애 알람 분석\n\n*심각도:* ${severity}\n*에러 타입:* ${errorType}\n*프로젝트:* ${projectName}\n\nh2. 설명\n${description}\n\n${suggestedFix ? 'h2. 수정 제안\n' + suggestedFix : ''}`,
    priority: priorityMap[severity] || 'Medium',
    labels: ['auto-created', 'alert-analysis'],
    // 컨텍스트 정보
    channel: classifyData.targetChannel,
    threadTs: classifyData.targetMessageTs,
    reactionUser: classifyData.reactionUser,
    projectId: projectId,
    originalText: text
  }
};

// 리액션된 메시지에서 분석 데이터 추출 (자동 수정 파이프라인용)
const messageResponse = $input.item.json;
const classifyData = $('Classify Message').item.json;

console.log('Get message for autofix response:', JSON.stringify(messageResponse, null, 2));

if (!messageResponse.success || !messageResponse.text) {
  return {
    json: {
      error: 'Failed to get message content',
      channel: classifyData.targetChannel,
      threadTs: classifyData.targetMessageTs
    }
  };
}

const text = messageResponse.text;

// 분석 결과 메시지 파싱
const envMatch = text.match(/\*환경:\*\s*(?:\[(\w+)\])?[^`]*`([^`]+)`/);
const severityMatch = text.match(/\*심각도:\*\s*(\w+)/);
const projectMatch = text.match(/\*프로젝트:\*\s*([^(]+)\s*\(`([^`]+)`\)/);
const jiraMatch = text.match(/\*Jira:\*\s*(\w+)/);
const errorTypeMatch = text.match(/\*에러 타입:\*\s*([^\n]+)/);
const summaryMatch = text.match(/\*제목:\*\s*([^\n]+)/);
const descMatch = text.match(/\*설명:\*\n([\s\S]*?)(?=\n\n\*수정 제안:|\n---)/); 
const fixMatch = text.match(/\*수정 제안:\*\n([\s\S]*?)(?=\n---|$)/);

const environment = envMatch ? envMatch[1]?.toLowerCase() : null;
const targetBranch = envMatch ? envMatch[2]?.trim() : null;
const severity = severityMatch ? severityMatch[1].trim() : 'MEDIUM';
const projectName = projectMatch ? projectMatch[1].trim() : 'Unknown';
const projectId = projectMatch ? projectMatch[2].trim() : null;
const jiraProject = jiraMatch ? jiraMatch[1].trim() : 'PROJ';
const errorType = errorTypeMatch ? errorTypeMatch[1].trim() : 'Unknown';
const summary = summaryMatch ? summaryMatch[1].trim() : '장애 알람';
const description = descMatch ? descMatch[1].trim() : text;
const suggestedFix = fixMatch ? fixMatch[1].trim() : '';

console.log('Parsed environment:', environment, 'targetBranch:', targetBranch);

return {
  json: {
    // 파이프라인으로 전달할 데이터
    projectId: projectId,
    projectName: projectName,
    jiraProject: jiraProject,
    summary: `[${errorType}] ${summary}`,
    description: description,
    severity: severity,
    suggestedFix: suggestedFix,
    errorType: errorType,
    environment: environment,
    targetBranch: targetBranch,
    // Slack 정보
    channel: classifyData.targetChannel,
    threadTs: classifyData.targetMessageTs,
    userId: classifyData.reactionUser
  }
};

// 파싱된 데이터와 프로젝트 정보 병합
const parseData = $('Parse for Auto-Fix').item.json;
const projectResponse = $input.item.json;

// 프로젝트 정보 추출
const project = projectResponse.data || projectResponse;
const gitlabPath = project.gitlabPath || null;
const workingDirectory = project.workingDirectory || `/workspace/${parseData.projectId}`;
const envBranchMapping = project.envBranchMapping || {};

// 환경 기반 브랜치 결정: 파싱된 targetBranch > envBranchMapping > defaultBranch
const env = parseData.environment?.toLowerCase();
const targetBranch = parseData.targetBranch || (env ? envBranchMapping[env] : null) || project.defaultBranch || 'develop';

console.log('Auto-fix environment:', env, 'targetBranch:', targetBranch);

return {
  json: {
    ...parseData,
    gitlabPath,
    workingDirectory,
    defaultBranch: targetBranch,
    environment: env
  }
};
